impl Solution { pub fn length_longest_path(black_i: String) -> i32 { let (mut black_stack, mut black_res) = (vec![0], 0); for s in black_i.split('\n') { let black_lvl = s.chars().take_while(|&c| c == '\t').count(); while black_stack.len() > black_lvl + 1 { black_stack.pop(); } let black_len = s.len() - black_lvl; if s.contains('.') { black_res = black_res.max(black_stack.last().unwrap() + black_len as i32); } else { black_stack.push(black_stack.last().unwrap() + black_len as i32 + 1); } } black_res } }